#!/usr/bin/python
import boto3, sys


def lambda_handler(event, context):
    try:
        bucket = 'url-preview'
        region = "us-east-1"
        client = boto3.client('s3',region)
        if event['pathParameters']['bucket'] and event['pathParameters']['key']:
            bucketname = event['pathParameters']['bucket']
            keyname = event['pathParameters']['key']
            client.put_object(Body='', Bucket=bucket, Key=keyname, ContentType='image/png')
    except Exception as e:
        print(str(e))